    87	// extractToolCallsFromGatewayLog reads gateway.jsonl and appends tool call records to mcpData.
    88	func extractToolCallsFromGatewayLog(gatewayLogPath string, mcpData *MCPToolUsageData) error {
    89		file, err := os.Open(gatewayLogPath)
    90		if err != nil {
    91			return fmt.Errorf("failed to open gateway.jsonl: %w", err)
    92		}
    93		defer file.Close()
    94	
    95		scanner := bufio.NewScanner(file)
    96		buf := make([]byte, maxScannerBufferSize)
    97		scanner.Buffer(buf, maxScannerBufferSize)
    98		for scanner.Scan() {
    99			line := strings.TrimSpace(scanner.Text())
   100			if line == "" {
   101				continue
   102			}
   103	
   104			var entry GatewayLogEntry
   105			if err := json.Unmarshal([]byte(line), &entry); err != nil {
   106				continue // Skip malformed lines
   107			}
   108	
   109			// Only process tool call events
   110			if entry.Event == "tool_call" || entry.Event == "rpc_call" || entry.Event == "request" {
   111				toolName := entry.ToolName
   112				if toolName == "" {
   113					toolName = entry.Method
   114				}
   115	
   116				// Skip entries without tool information
   117				if entry.ServerName == "" || toolName == "" {
   118					continue
   119				}
   120	
   121				// Create individual tool call record
   122				toolCall := MCPToolCall{
   123					Timestamp:  entry.Timestamp,
   124					ServerName: entry.ServerName,
   125					ToolName:   toolName,
   126					Method:     entry.Method,
   127					InputSize:  entry.InputSize,
   128					OutputSize: entry.OutputSize,
   129					Status:     entry.Status,
   130					Error:      entry.Error,
   131				}
   132	
   133				if entry.Duration > 0 {
   134					toolCall.Duration = timeutil.FormatDuration(time.Duration(entry.Duration * float64(time.Millisecond)))
   135				}
   136	
   137				mcpData.ToolCalls = append(mcpData.ToolCalls, toolCall)
   138			}
   139		}
   140	
   141		if err := scanner.Err(); err != nil {
   142			return fmt.Errorf("error reading gateway.jsonl: %w", err)
   143		}
   144		return nil
   145	}
