   147	// buildMCPSummaryStats populates mcpData.Summary and mcpData.Servers from aggregated gateway metrics.
   148	func buildMCPSummaryStats(gatewayMetrics *GatewayMetrics, mcpData *MCPToolUsageData) {
   149		for serverName, serverMetrics := range gatewayMetrics.Servers {
   150			// Server-level stats
   151			serverStats := MCPServerStats{
   152				ServerName:      serverName,
   153				RequestCount:    serverMetrics.RequestCount,
   154				ToolCallCount:   serverMetrics.ToolCallCount,
   155				TotalInputSize:  0,
   156				TotalOutputSize: 0,
   157				ErrorCount:      serverMetrics.ErrorCount,
   158			}
   159	
   160			if serverMetrics.RequestCount > 0 {
   161				avgDur := serverMetrics.TotalDuration / float64(serverMetrics.RequestCount)
   162				serverStats.AvgDuration = timeutil.FormatDuration(time.Duration(avgDur * float64(time.Millisecond)))
   163			}
   164	
   165			// Tool-level stats
   166			for toolName, toolMetrics := range serverMetrics.Tools {
   167				summary := MCPToolSummary{
   168					ServerName:      serverName,
   169					ToolName:        toolName,
   170					CallCount:       toolMetrics.CallCount,
   171					TotalInputSize:  toolMetrics.TotalInputSize,
   172					TotalOutputSize: toolMetrics.TotalOutputSize,
   173					MaxInputSize:    0, // Will be calculated below
   174					MaxOutputSize:   0, // Will be calculated below
   175					ErrorCount:      toolMetrics.ErrorCount,
   176				}
   177	
   178				if toolMetrics.AvgDuration > 0 {
   179					summary.AvgDuration = timeutil.FormatDuration(time.Duration(toolMetrics.AvgDuration * float64(time.Millisecond)))
   180				}
   181				if toolMetrics.MaxDuration > 0 {
   182					summary.MaxDuration = timeutil.FormatDuration(time.Duration(toolMetrics.MaxDuration * float64(time.Millisecond)))
   183				}
   184	
   185				// Calculate max input/output sizes from individual tool calls
   186				for _, tc := range mcpData.ToolCalls {
   187					if tc.ServerName == serverName && tc.ToolName == toolName {
   188						if tc.InputSize > summary.MaxInputSize {
   189							summary.MaxInputSize = tc.InputSize
   190						}
   191						if tc.OutputSize > summary.MaxOutputSize {
   192							summary.MaxOutputSize = tc.OutputSize
   193						}
   194					}
   195				}
   196	
   197				mcpData.Summary = append(mcpData.Summary, summary)
   198	
   199				// Update server totals
   200				serverStats.TotalInputSize += toolMetrics.TotalInputSize
   201				serverStats.TotalOutputSize += toolMetrics.TotalOutputSize
   202			}
   203	
   204			mcpData.Servers = append(mcpData.Servers, serverStats)
   205		}
   206	
   207		// Sort summaries by server name, then tool name
   208		sort.Slice(mcpData.Summary, func(i, j int) bool {
   209			if mcpData.Summary[i].ServerName != mcpData.Summary[j].ServerName {
   210				return mcpData.Summary[i].ServerName < mcpData.Summary[j].ServerName
   211			}
   212			return mcpData.Summary[i].ToolName < mcpData.Summary[j].ToolName
   213		})
   214	
   215		// Sort servers by name
   216		sort.Slice(mcpData.Servers, func(i, j int) bool {
   217			return mcpData.Servers[i].ServerName < mcpData.Servers[j].ServerName
   218		})
   219	}

