func mergeMCPToolUsageInfo(toolUsage []ToolUsageInfo, mcpToolUsage *MCPToolUsageData) []ToolUsageInfo {
	if mcpToolUsage == nil || (len(mcpToolUsage.Summary) == 0 && len(mcpToolUsage.ToolCalls) == 0) {
		return toolUsage
	}

	toolStats := make(map[string]*ToolUsageInfo, len(toolUsage)+len(mcpToolUsage.Summary))
	for i := range toolUsage {
		info := toolUsage[i]
		toolStats[info.Name] = &info
	}

	for _, summary := range mcpToolUsage.Summary {
		mergeMCPToolSummary(toolStats, summary)
	}
	for _, toolCall := range mcpToolUsage.ToolCalls {
		mergeMCPToolCall(toolStats, toolCall)
	}

	merged := make([]ToolUsageInfo, 0, len(toolStats))
	for _, info := range toolStats {
		merged = append(merged, *info)
	}
	sortToolUsageInfo(merged)
	return merged
}

func mergeMCPToolSummary(toolStats map[string]*ToolUsageInfo, summary MCPToolSummary) {
	if summary.ServerName == "" || summary.ToolName == "" || summary.CallCount <= 0 {
		return
	}

	name := workflow.PrettifyToolName(fmt.Sprintf("mcp__%s__%s", summary.ServerName, summary.ToolName))
	if existing, exists := toolStats[name]; exists {
		if existing.CallCount == 0 {
			existing.CallCount = summary.CallCount
		}
		if summary.MaxInputSize > existing.MaxInputSize {
			existing.MaxInputSize = summary.MaxInputSize
		}
		if summary.MaxOutputSize > existing.MaxOutputSize {
			existing.MaxOutputSize = summary.MaxOutputSize
		}
		return
	}

	toolStats[name] = &ToolUsageInfo{
		Name:          name,
		CallCount:     summary.CallCount,
		MaxInputSize:  summary.MaxInputSize,
		MaxOutputSize: summary.MaxOutputSize,
		MaxDuration:   summary.MaxDuration,
	}
}

func mergeMCPToolCall(toolStats map[string]*ToolUsageInfo, toolCall MCPToolCall) {
	if toolCall.ServerName == "" || toolCall.ToolName == "" {
		return
	}

	name := workflow.PrettifyToolName(fmt.Sprintf("mcp__%s__%s", toolCall.ServerName, toolCall.ToolName))
	if _, exists := toolStats[name]; exists {
		return
	}

	toolStats[name] = &ToolUsageInfo{
		Name:          name,
		CallCount:     1,
		MaxInputSize:  toolCall.InputSize,
		MaxOutputSize: toolCall.OutputSize,
		MaxDuration:   toolCall.Duration,
	}
}

