func mergeMCPToolUsageInfo(toolUsage []ToolUsageInfo, mcpToolUsage *MCPToolUsageData) []ToolUsageInfo {
	if mcpToolUsage == nil || (len(mcpToolUsage.Summary) == 0 && len(mcpToolUsage.ToolCalls) == 0) {
		return toolUsage
	}

	toolStats := make(map[string]*ToolUsageInfo, len(toolUsage)+len(mcpToolUsage.Summary))
	for _, info := range toolUsage {
		infoCopy := info
		toolStats[infoCopy.Name] = &infoCopy
	}

	summaryTools := make(map[string]bool, len(mcpToolUsage.Summary))
	for _, summary := range mcpToolUsage.Summary {
		name := mcpToolUsageInfoName(summary.ServerName, summary.ToolName)
		if name == "" {
			continue
		}
		summaryTools[name] = true
		mergeMCPToolSummary(toolStats, name, summary)
	}
	for _, toolCall := range mcpToolUsage.ToolCalls {
		name := mcpToolUsageInfoName(toolCall.ServerName, toolCall.ToolName)
		if name == "" || summaryTools[name] {
			continue
		}
		mergeMCPToolCall(toolStats, name, toolCall)
	}

	merged := make([]ToolUsageInfo, 0, len(toolStats))
	for _, info := range toolStats {
		merged = append(merged, *info)
	}
	sortToolUsageInfo(merged)
	return merged
}

func mcpToolUsageInfoName(serverName, toolName string) string {
	if serverName == "" || toolName == "" {
		return ""
	}
	return workflow.PrettifyToolName(fmt.Sprintf("mcp__%s__%s", serverName, toolName))
}

func mergeMCPToolSummary(toolStats map[string]*ToolUsageInfo, name string, summary MCPToolSummary) {
	if summary.CallCount <= 0 {
		return
	}

	if existing, exists := toolStats[name]; exists {
		if existing.CallCount == 0 {
			existing.CallCount = summary.CallCount
		}
		if summary.MaxInputSize > existing.MaxInputSize {
			existing.MaxInputSize = summary.MaxInputSize
		}
		if summary.MaxOutputSize > existing.MaxOutputSize {
			existing.MaxOutputSize = summary.MaxOutputSize
		}
		return
	}

	toolStats[name] = &ToolUsageInfo{
		Name:          name,
		CallCount:     summary.CallCount,
		MaxInputSize:  summary.MaxInputSize,
		MaxOutputSize: summary.MaxOutputSize,
		MaxDuration:   summary.MaxDuration,
	}
}

func mergeMCPToolCall(toolStats map[string]*ToolUsageInfo, name string, toolCall MCPToolCall) {
	if existing, exists := toolStats[name]; exists {
		existing.CallCount++
		if toolCall.InputSize > existing.MaxInputSize {
			existing.MaxInputSize = toolCall.InputSize
		}
		if toolCall.OutputSize > existing.MaxOutputSize {
			existing.MaxOutputSize = toolCall.OutputSize
		}
		return
	}

	toolStats[name] = &ToolUsageInfo{
		Name:          name,
		CallCount:     1,
		MaxInputSize:  toolCall.InputSize,
		MaxOutputSize: toolCall.OutputSize,
		MaxDuration:   toolCall.Duration,
	}
